patch:
--- a/alu_32bit.v
+++ b/alu_32bit.v
@@ -1,10 +1,10 @@
 module alu_32bit(
   input [31:0] operand_x, operand_y,
   input [2:0] operation,
   output reg [31:0] result
 );

-  always @(operand_x or operation)
+  always @(*)
     case(operation)
       3'b000: result = operand_x + operand_y;
       3'b001: result = operand_x - operand_y;

before_code:
module alu_32bit(
  input [31:0] operand_x, operand_y,
  input [2:0] operation,
  output reg [31:0] result
);

  always @(operand_x or operation)
    case(operation)
      3'b000: result = operand_x + operand_y;
      3'b001: result = operand_x - operand_y;
      3'b010: result = operand_x & operand_y;
      3'b011: result = operand_x | operand_y;
      3'b100: result = operand_x ^ operand_y;
      default: result = 32'b0;
    endcase

endmodule

after_code:
module alu_32bit(
  input [31:0] operand_x, operand_y,
  input [2:0] operation,
  output reg [31:0] result
);

  always @(*)
    case(operation)
      3'b000: result = operand_x + operand_y;
      3'b001: result = operand_x - operand_y;
      3'b010: result = operand_x & operand_y;
      3'b011: result = operand_x | operand_y;
      3'b100: result = operand_x ^ operand_y;
      default: result = 32'b0;
    endcase

endmodule
